import fs from "fs";
import os from "os";
import path from "path";
import { runRadar } from "./pipeline";
import type { RadarResult, Play } from "./types";

const PLAYS_FILE = path.join(process.cwd(), "data", "plays.json");
// A re-run on a read-only host writes here (see /api/run-radar); prefer it if present.
const TMP_PLAYS = path.join(os.tmpdir(), "westbrook-plays.json");

// Read the pre-baked weekly run (deterministic — generated by `npm run radar`).
// Falls back to running the pipeline live if the file isn't there yet.
export async function getRadar(): Promise<RadarResult> {
  for (const file of [TMP_PLAYS, PLAYS_FILE]) {
    if (fs.existsSync(file)) return JSON.parse(fs.readFileSync(file, "utf8")) as RadarResult;
  }
  return runRadar();
}

export async function getPlay(id: string): Promise<Play | null> {
  const r = await getRadar();
  return r.plays.find((p) => p.id === id) ?? null;
}
